package com.guilherme.emobiliaria.config.infrastructure.repository;

import com.guilherme.emobiliaria.config.domain.entity.Config;
import com.guilherme.emobiliaria.config.domain.repository.ConfigRepository;
import com.guilherme.emobiliaria.person.domain.entity.Address;
import com.guilherme.emobiliaria.person.domain.entity.BrazilianState;
import com.guilherme.emobiliaria.person.domain.entity.CivilState;
import com.guilherme.emobiliaria.person.domain.entity.JuridicalPerson;
import com.guilherme.emobiliaria.person.domain.entity.Person;
import com.guilherme.emobiliaria.person.domain.entity.PhysicalPerson;
import com.guilherme.emobiliaria.shared.exception.ErrorMessage;
import com.guilherme.emobiliaria.shared.exception.PersistenceException;
import jakarta.inject.Inject;

import javax.sql.DataSource;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class JdbcConfigRepository implements ConfigRepository {

  private final DataSource dataSource;

  @Inject
  public JdbcConfigRepository(DataSource dataSource) {
    this.dataSource = dataSource;
  }

  @Override
  public Config get() {
    String sql = "SELECT id, default_landlord_id, default_landlord_type FROM configs WHERE id = 1";
    try (Connection conn = dataSource.getConnection();
        PreparedStatement stmt = conn.prepareStatement(sql);
        ResultSet rs = stmt.executeQuery()) {
      rs.next();
      return map(rs, conn);
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Config.NOT_FOUND, e);
    }
  }

  @Override
  public Config set(Config config) {
    String sql = "UPDATE configs SET default_landlord_id = ?, default_landlord_type = ? WHERE id = 1";
    try (Connection conn = dataSource.getConnection();
        PreparedStatement stmt = conn.prepareStatement(sql)) {
      if (config.getDefaultLandlord() == null) {
        stmt.setNull(1, java.sql.Types.BIGINT);
        stmt.setNull(2, java.sql.Types.VARCHAR);
      } else {
        stmt.setLong(1, config.getDefaultLandlord().getId());
        stmt.setString(2, personType(config.getDefaultLandlord()));
      }
      stmt.executeUpdate();
      return config;
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Config.NOT_FOUND, e);
    }
  }

  private Config map(ResultSet rs, Connection conn) throws SQLException {
    long id = rs.getLong("id");
    long landlordId = rs.getLong("default_landlord_id");
    String landlordType = rs.getString("default_landlord_type");

    Person defaultLandlord = null;
    if (!rs.wasNull() && landlordType != null) {
      defaultLandlord = loadPerson(conn, landlordId, landlordType);
    }

    return Config.restore(id, defaultLandlord);
  }

  private Person loadPerson(Connection conn, long id, String type) throws SQLException {
    if ("PHYSICAL".equals(type)) {
      return loadPhysicalPerson(conn, id);
    }
    return loadJuridicalPerson(conn, id);
  }

  private PhysicalPerson loadPhysicalPerson(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, name, nationality, civil_state, occupation, cpf, id_card_number, address_id FROM physical_persons WHERE id = ?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        Address address = loadAddress(conn, rs.getLong("address_id"));
        return PhysicalPerson.restore(
            rs.getLong("id"),
            rs.getString("name"),
            rs.getString("nationality"),
            CivilState.valueOf(rs.getString("civil_state")),
            rs.getString("occupation"),
            rs.getString("cpf"),
            rs.getString("id_card_number"),
            address
        );
      }
    }
  }

  private JuridicalPerson loadJuridicalPerson(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, corporate_name, cnpj, representative_id, address_id FROM juridical_persons WHERE id = ?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        PhysicalPerson representative = loadPhysicalPerson(conn, rs.getLong("representative_id"));
        Address address = loadAddress(conn, rs.getLong("address_id"));
        return JuridicalPerson.restore(
            rs.getLong("id"),
            rs.getString("corporate_name"),
            rs.getString("cnpj"),
            representative,
            address
        );
      }
    }
  }

  private Address loadAddress(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, cep, address, number, complement, neighborhood, city, state FROM addresses WHERE id = ?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        return Address.restore(
            rs.getLong("id"),
            rs.getString("cep"),
            rs.getString("address"),
            rs.getString("number"),
            rs.getString("complement"),
            rs.getString("neighborhood"),
            rs.getString("city"),
            BrazilianState.valueOf(rs.getString("state"))
        );
      }
    }
  }

  private String personType(Person person) {
    return person instanceof PhysicalPerson ? "PHYSICAL" : "JURIDICAL";
  }
}

package com.guilherme.emobiliaria.config.infrastructure.repository;

import com.guilherme.emobiliaria.config.domain.entity.Config;
import com.guilherme.emobiliaria.config.domain.repository.ConfigRepository;
import com.guilherme.emobiliaria.person.domain.entity.Address;
import com.guilherme.emobiliaria.person.domain.entity.BrazilianState;
import com.guilherme.emobiliaria.person.domain.entity.CivilState;
import com.guilherme.emobiliaria.person.domain.entity.JuridicalPerson;
import com.guilherme.emobiliaria.person.domain.entity.Person;
import com.guilherme.emobiliaria.person.domain.entity.PhysicalPerson;
import com.guilherme.emobiliaria.shared.exception.ErrorMessage;
import com.guilherme.emobiliaria.shared.exception.PersistenceException;
import jakarta.inject.Inject;

import javax.sql.DataSource;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.ArrayList;
import java.util.List;

public class JdbcConfigRepository implements ConfigRepository {

  private final DataSource dataSource;

  @Inject
  public JdbcConfigRepository(DataSource dataSource) {
    this.dataSource = dataSource;
  }

  @Override
  public Config get() {
    String sql = "SELECT id, default_landlord_id, default_landlord_type FROM configs WHERE id = 1";
    try (Connection conn = dataSource.getConnection();
        PreparedStatement stmt = conn.prepareStatement(sql);
        ResultSet rs = stmt.executeQuery()) {
      rs.next();
      return map(rs, conn);
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Config.NOT_FOUND, e);
    }
  }

  @Override
  public Config set(Config config) {
    String sql = "UPDATE configs SET default_landlord_id = ?, default_landlord_type = ? WHERE id = 1";
    try (Connection conn = dataSource.getConnection();
        PreparedStatement stmt = conn.prepareStatement(sql)) {
      if (config.getDefaultLandlord() == null) {
        stmt.setNull(1, java.sql.Types.BIGINT);
        stmt.setNull(2, java.sql.Types.VARCHAR);
      } else {
        stmt.setLong(1, config.getDefaultLandlord().getId());
        stmt.setString(2, personType(config.getDefaultLandlord()));
      }
      stmt.executeUpdate();
      return config;
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Config.NOT_FOUND, e);
    }
  }

  private Config map(ResultSet rs, Connection conn) throws SQLException {
    long id = rs.getLong("id");
    long landlordId = rs.getLong("default_landlord_id");
    String landlordType = rs.getString("default_landlord_type");

    Person defaultLandlord = null;
    if (!rs.wasNull() && landlordType != null) {
      defaultLandlord = loadPerson(conn, landlordId, landlordType);
    }

    return Config.restore(id, defaultLandlord);
  }

  private Person loadPerson(Connection conn, long id, String type) throws SQLException {
    if ("PHYSICAL".equals(type)) {
      return loadPhysicalPerson(conn, id);
    }
    return loadJuridicalPerson(conn, id);
  }

  private PhysicalPerson loadPhysicalPerson(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, name, nationality, civil_state, occupation, cpf, id_card_number, address_id FROM physical_persons WHERE id = ?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        Address address = loadAddress(conn, rs.getLong("address_id"));
        return PhysicalPerson.restore(
            rs.getLong("id"),
            rs.getString("name"),
            rs.getString("nationality"),
            CivilState.valueOf(rs.getString("civil_state")),
            rs.getString("occupation"),
            rs.getString("cpf"),
            rs.getString("id_card_number"),
            address
        );
      }
    }
  }

  private JuridicalPerson loadJuridicalPerson(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, corporate_name, cnpj, address_id FROM juridical_persons WHERE id = ?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        List<PhysicalPerson> representatives = loadRepresentatives(conn, rs.getLong("id"));
        Address address = loadAddress(conn, rs.getLong("address_id"));
        return JuridicalPerson.restore(
            rs.getLong("id"),
            rs.getString("corporate_name"),
            rs.getString("cnpj"),
            representatives,
            address
        );
      }
    }
  }

  private List<PhysicalPerson> loadRepresentatives(Connection conn, long juridicalPersonId) throws SQLException {
    String sql = "SELECT physical_person_id FROM juridical_person_representatives WHERE juridical_person_id=?";
    List<PhysicalPerson> representatives = new ArrayList<>();
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, juridicalPersonId);
      try (ResultSet rs = stmt.executeQuery()) {
        while (rs.next()) {
          representatives.add(loadPhysicalPerson(conn, rs.getLong("physical_person_id")));
        }
      }
    }
    return representatives;
  }

  private Address loadAddress(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, cep, address, number, complement, neighborhood, city, state FROM addresses WHERE id = ?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        return Address.restore(
            rs.getLong("id"),
            rs.getString("cep"),
            rs.getString("address"),
            rs.getString("number"),
            rs.getString("complement"),
            rs.getString("neighborhood"),
            rs.getString("city"),
            BrazilianState.valueOf(rs.getString("state"))
        );
      }
    }
  }

  private String personType(Person person) {
    return person instanceof PhysicalPerson ? "PHYSICAL" : "JURIDICAL";
  }
}

package com.guilherme.emobiliaria.config.ui.controller;

import com.guilherme.emobiliaria.config.application.input.SetConfigInput;
import com.guilherme.emobiliaria.config.application.usecase.SetConfigInteractor;
import com.guilherme.emobiliaria.config.ui.component.PersonType;
import com.guilherme.emobiliaria.config.ui.component.PersonTypeSelectionPane;
import com.guilherme.emobiliaria.person.application.input.CreateJuridicalPersonInput;
import com.guilherme.emobiliaria.person.application.output.CreateAddressOutput;
import com.guilherme.emobiliaria.person.application.output.CreateJuridicalPersonOutput;
import com.guilherme.emobiliaria.person.application.output.CreatePhysicalPersonOutput;
import com.guilherme.emobiliaria.person.application.usecase.CreateAddressInteractor;
import com.guilherme.emobiliaria.person.application.usecase.CreateJuridicalPersonInteractor;
import com.guilherme.emobiliaria.person.application.usecase.CreatePhysicalPersonInteractor;
import com.guilherme.emobiliaria.person.application.usecase.SearchAddressByCepInteractor;
import com.guilherme.emobiliaria.person.application.usecase.ValidateCnpjInteractor;
import com.guilherme.emobiliaria.person.application.usecase.ValidateCpfInteractor;
import com.guilherme.emobiliaria.person.ui.component.AddressFormPane;
import com.guilherme.emobiliaria.person.ui.component.CompanyDataFormPane;
import com.guilherme.emobiliaria.person.ui.component.PhysicalPersonFormPane;
import com.guilherme.emobiliaria.shared.di.GuiceFxmlLoader;
import com.guilherme.emobiliaria.shared.ui.ErrorHandler;
import com.guilherme.emobiliaria.shared.ui.component.WizardStepperBar;
import jakarta.inject.Inject;
import javafx.application.Platform;
import javafx.concurrent.Task;
import javafx.fxml.FXML;
import javafx.scene.Node;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.StackPane;
import javafx.stage.Stage;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;
import java.util.ResourceBundle;

public class InitialSetupController {

  private static final Logger log = LoggerFactory.getLogger(InitialSetupController.class);

  // ── Injected use cases ─────────────────────────────────────────────────────

  private final CreateAddressInteractor createAddress;
  private final SearchAddressByCepInteractor searchByCep;
  private final CreatePhysicalPersonInteractor createPhysicalPerson;
  private final CreateJuridicalPersonInteractor createJuridicalPerson;
  private final SetConfigInteractor setConfig;
  private final ValidateCpfInteractor validateCpf;
  private final ValidateCnpjInteractor validateCnpj;
  private final GuiceFxmlLoader fxmlLoader;

  @Inject
  public InitialSetupController(
      CreateAddressInteractor createAddress,
      SearchAddressByCepInteractor searchByCep,
      CreatePhysicalPersonInteractor createPhysicalPerson,
      CreateJuridicalPersonInteractor createJuridicalPerson, SetConfigInteractor setConfig,
      ValidateCpfInteractor validateCpf, ValidateCnpjInteractor validateCnpj,
      GuiceFxmlLoader fxmlLoader) {
    this.createAddress = createAddress;
    this.searchByCep = searchByCep;
    this.createPhysicalPerson = createPhysicalPerson;
    this.createJuridicalPerson = createJuridicalPerson;
    this.setConfig = setConfig;
    this.validateCpf = validateCpf;
    this.validateCnpj = validateCnpj;
    this.fxmlLoader = fxmlLoader;
  }

  // ── FXML fields ────────────────────────────────────────────────────────────

  @FXML private Label stepTitleLabel;
  @FXML private Label stepSubtitleLabel;
  @FXML private HBox stepperContainer;
  @FXML private StackPane contentPane;
  @FXML private Button backButton;
  @FXML private Button nextButton;

  // ── Wizard state ───────────────────────────────────────────────────────────

  private int currentStep = 1;
  private PersonType selectedType = null;
  private ResourceBundle bundle;

  // ── UI components ──────────────────────────────────────────────────────────

  private static final String[][] STEP_LABELS_PHYSICAL =
      {{"stepper.label.tipo"}, {"stepper.label.dados"}, {"stepper.label.endereco"}};
  private static final String[][] STEP_LABELS_JURIDICAL =
      {{"stepper.label.tipo"}, {"stepper.label.empresa"}, {"stepper.label.end_empresa"},
          {"stepper.label.representante"}, {"stepper.label.end_repres"}};
  private final AddressFormPane[] addressPane = new AddressFormPane[2];
  private PersonTypeSelectionPane typeSelectionPane;
  private PhysicalPersonFormPane physicalPersonForm;

  // ── Step label keys ────────────────────────────────────────────────────────
  private CompanyDataFormPane companyDataForm;
  private WizardStepperBar stepperBar;

  // ── Initialization ─────────────────────────────────────────────────────────

  @FXML
  public void initialize() {
    bundle = ResourceBundle.getBundle("messages", Locale.getDefault(),
        getClass().getModule());

    typeSelectionPane = new PersonTypeSelectionPane(bundle);
    physicalPersonForm = new PhysicalPersonFormPane(bundle, validateCpf);
    companyDataForm = new CompanyDataFormPane(bundle, validateCnpj);
    addressPane[0] = new AddressFormPane(searchByCep, bundle);
    addressPane[1] = new AddressFormPane(searchByCep, bundle);

    addressPane[0].setDisableNextCallback(() -> nextButton.setDisable(true),
        () -> nextButton.setDisable(false));
    addressPane[1].setDisableNextCallback(() -> nextButton.setDisable(true),
        () -> nextButton.setDisable(false));

    buildStepper();
    showStep(1);
    backButton.setOnAction(e -> handleBack());
    nextButton.setOnAction(e -> handleNext());
  }

  // ── Stepper ────────────────────────────────────────────────────────────────

  private void buildStepper() {
    List<String> labelTexts = getStepperLabelTexts();
    stepperBar = new WizardStepperBar(labelTexts);
    HBox.setHgrow(stepperBar, Priority.ALWAYS);
    stepperContainer.getChildren().setAll(stepperBar);
    stepperBar.setCurrentStep(currentStep);
  }

  private List<String> getStepperLabelTexts() {
    String[][] keys = (selectedType == PersonType.JURIDICAL)
        ? STEP_LABELS_JURIDICAL : STEP_LABELS_PHYSICAL;
    List<String> texts = new ArrayList<>();
    for (String[] key : keys) {
      texts.add(bundle.getString(key[0]));
    }
    return texts;
  }

  // ── Step navigation ────────────────────────────────────────────────────────

  private void showStep(int step) {
    contentPane.getChildren().clear();

    stepTitleLabel.setText(bundle.getString(titleKeyForStep(step)));
    stepSubtitleLabel.setText(bundle.getString(subtitleKeyForStep(step)));

    backButton.setVisible(step > 1);
    backButton.setManaged(step > 1);
    backButton.setText(bundle.getString("setup.button.back"));

    boolean isLastStep = isLastStep(step);
    nextButton.setText(isLastStep
        ? bundle.getString("setup.button.finish")
        : bundle.getString("setup.button.next"));

    contentPane.getChildren().add(buildStepContent(step));
    stepperBar.setCurrentStep(step);
  }

  private String titleKeyForStep(int step) {
    if (step == 1) return "setup.step.type.title";
    if (selectedType == PersonType.JURIDICAL) {
      return switch (step) {
        case 2 -> "setup.step.company.title";
        case 3 -> "setup.step.company_address.title";
        case 4 -> "setup.step.representative.title";
        case 5 -> "setup.step.representative_address.title";
        default -> "setup.step.type.title";
      };
    }
    return switch (step) {
      case 2 -> "setup.step.personal.title";
      case 3 -> "setup.step.address.title";
      default -> "setup.step.type.title";
    };
  }

  private String subtitleKeyForStep(int step) {
    if (step == 1) return "setup.step.type.subtitle";
    if (selectedType == PersonType.JURIDICAL) {
      return switch (step) {
        case 2 -> "setup.step.company.subtitle";
        case 3 -> "setup.step.company_address.subtitle";
        case 4 -> "setup.step.representative.subtitle";
        case 5 -> "setup.step.representative_address.subtitle";
        default -> "setup.step.type.subtitle";
      };
    }
    return switch (step) {
      case 2 -> "setup.step.personal.subtitle";
      case 3 -> "setup.step.address.subtitle";
      default -> "setup.step.type.subtitle";
    };
  }

  private boolean isLastStep(int step) {
    if (selectedType == PersonType.PHYSICAL) return step == 3;
    if (selectedType == PersonType.JURIDICAL) return step == 5;
    return false;
  }

  private Node buildStepContent(int step) {
    if (step == 1)
      return typeSelectionPane;
    if (selectedType == PersonType.JURIDICAL) {
      return switch (step) {
        case 2 -> companyDataForm;
        case 3 -> addressPane[0];
        case 4 -> physicalPersonForm;
        case 5 -> addressPane[1];
        default -> typeSelectionPane;
      };
    }
    return switch (step) {
      case 2 -> physicalPersonForm;
      case 3 -> addressPane[0];
      default -> typeSelectionPane;
    };
  }

  private void handleNext() {
    if (!validateCurrentStep()) return;

    if (currentStep == 1) {
      selectedType = typeSelectionPane.getSelectedType();
      buildStepper();
    }

    if (isLastStep(currentStep)) {
      handleSubmit();
      return;
    }

    currentStep++;
    showStep(currentStep);
  }

  private void handleBack() {
    if (currentStep <= 1) return;
    currentStep--;
    showStep(currentStep);
  }

  // ── Validation ─────────────────────────────────────────────────────────────

  private boolean validateCurrentStep() {
    if (currentStep == 1)
      return typeSelectionPane.validate();

    if (selectedType == PersonType.JURIDICAL) {
      return switch (currentStep) {
        case 2 -> companyDataForm.validate();
        case 3 -> addressPane[0].validate();
        case 4 -> physicalPersonForm.validate();
        case 5 -> addressPane[1].validate();
        default -> true;
      };
    }
    return switch (currentStep) {
      case 2 -> physicalPersonForm.validate();
      case 3 -> addressPane[0].validate();
      default -> true;
    };
  }

  // ── Submission ─────────────────────────────────────────────────────────────

  private void handleSubmit() {
    nextButton.setDisable(true);
    backButton.setDisable(true);

    if (selectedType == PersonType.PHYSICAL) {
      submitPhysicalFlow();
    } else {
      submitJuridicalFlow();
    }
  }

  private void submitPhysicalFlow() {
    Task<CreateAddressOutput> addressTask = new Task<>() {
      @Override protected CreateAddressOutput call() {
        return createAddress.execute(addressPane[0].buildInput());
      }
    };

    addressTask.setOnSucceeded(e -> {
      long addressId = addressTask.getValue().address().getId();

      Task<CreatePhysicalPersonOutput> personTask = new Task<>() {
        @Override protected CreatePhysicalPersonOutput call() {
          return createPhysicalPerson.execute(physicalPersonForm.buildInput(addressId));
        }
      };

      personTask.setOnSucceeded(pe -> {
        long personId = personTask.getValue().physicalPerson().getId();

        Task<Void> configTask = new Task<>() {
          @Override protected Void call() {
            setConfig.execute(new SetConfigInput(personId, "PHYSICAL"));
            return null;
          }
        };

        configTask.setOnSucceeded(ce -> navigateToMain());
        configTask.setOnFailed(ce -> handleError(configTask.getException()));
        new Thread(configTask).start();
      });

      personTask.setOnFailed(pe -> handleError(personTask.getException()));
      new Thread(personTask).start();
    });

    addressTask.setOnFailed(e -> handleError(addressTask.getException()));
    new Thread(addressTask).start();
  }

  private void submitJuridicalFlow() {
    Task<CreateAddressOutput> companyAddrTask = new Task<>() {
      @Override protected CreateAddressOutput call() {
        return createAddress.execute(addressPane[0].buildInput());
      }
    };

    companyAddrTask.setOnSucceeded(e -> {
      long companyAddressId = companyAddrTask.getValue().address().getId();

      Task<CreateAddressOutput> reprAddrTask = new Task<>() {
        @Override protected CreateAddressOutput call() {
          return createAddress.execute(addressPane[1].buildInput());
        }
      };

      reprAddrTask.setOnSucceeded(e2 -> {
        long reprAddressId = reprAddrTask.getValue().address().getId();

        Task<CreatePhysicalPersonOutput> reprPersonTask = new Task<>() {
          @Override protected CreatePhysicalPersonOutput call() {
            return createPhysicalPerson.execute(physicalPersonForm.buildInput(reprAddressId));
          }
        };

        reprPersonTask.setOnSucceeded(e3 -> {
          long reprPersonId = reprPersonTask.getValue().physicalPerson().getId();

          Task<CreateJuridicalPersonOutput> juridicalTask = new Task<>() {
            @Override protected CreateJuridicalPersonOutput call() {
              return createJuridicalPerson.execute(new CreateJuridicalPersonInput(
                  companyDataForm.getCorporateName(), companyDataForm.getCnpj(),
                  reprPersonId,
                  companyAddressId
              ));
            }
          };

          juridicalTask.setOnSucceeded(e4 -> {
            long juridicalId = juridicalTask.getValue().juridicalPerson().getId();

            Task<Void> configTask = new Task<>() {
              @Override protected Void call() {
                setConfig.execute(new SetConfigInput(juridicalId, "JURIDICAL"));
                return null;
              }
            };

            configTask.setOnSucceeded(e5 -> navigateToMain());
            configTask.setOnFailed(e5 -> handleError(configTask.getException()));
            new Thread(configTask).start();
          });

          juridicalTask.setOnFailed(e4 -> handleError(juridicalTask.getException()));
          new Thread(juridicalTask).start();
        });

        reprPersonTask.setOnFailed(e3 -> handleError(reprPersonTask.getException()));
        new Thread(reprPersonTask).start();
      });

      reprAddrTask.setOnFailed(e2 -> handleError(reprAddrTask.getException()));
      new Thread(reprAddrTask).start();
    });

    companyAddrTask.setOnFailed(e -> handleError(companyAddrTask.getException()));
    new Thread(companyAddrTask).start();
  }

  private void navigateToMain() {
    try {
      Stage stage = (Stage) nextButton.getScene().getWindow();
      Parent mainView = fxmlLoader.load(InitialSetupController.class.getResource(
          "/com/guilherme/emobiliaria/shared/ui/layout/view/main-view.fxml"));
      Scene scene = new Scene(mainView);
      stage.setScene(scene);
      stage.setTitle("e-Mobiliária");
      stage.setResizable(true);
    } catch (IOException e) {
      log.error("Failed to load main view", e);
      handleError(e);
    }
  }

  private void handleError(Throwable t) {
    Platform.runLater(() -> {
      nextButton.setDisable(false);
      backButton.setDisable(false);
    });
    ErrorHandler.handle(t, bundle);
  }
}

package com.guilherme.emobiliaria.config.ui.controller;

import com.guilherme.emobiliaria.config.application.input.SetConfigInput;
import com.guilherme.emobiliaria.config.application.usecase.SetConfigInteractor;
import com.guilherme.emobiliaria.config.ui.component.PersonType;
import com.guilherme.emobiliaria.config.ui.component.PersonTypeSelectionPane;
import com.guilherme.emobiliaria.person.application.input.CreateJuridicalPersonInput;
import com.guilherme.emobiliaria.person.application.output.CreateAddressOutput;
import com.guilherme.emobiliaria.person.application.output.CreateJuridicalPersonOutput;
import com.guilherme.emobiliaria.person.application.output.CreatePhysicalPersonOutput;
import com.guilherme.emobiliaria.person.application.usecase.CreateAddressInteractor;
import com.guilherme.emobiliaria.person.application.usecase.CreateJuridicalPersonInteractor;
import com.guilherme.emobiliaria.person.application.usecase.CreatePhysicalPersonInteractor;
import com.guilherme.emobiliaria.person.application.usecase.SearchAddressByCepInteractor;
import com.guilherme.emobiliaria.person.application.usecase.ValidateCnpjInteractor;
import com.guilherme.emobiliaria.person.application.usecase.ValidateCpfInteractor;
import com.guilherme.emobiliaria.person.ui.component.AddressFormPane;
import com.guilherme.emobiliaria.person.ui.component.CompanyDataFormPane;
import com.guilherme.emobiliaria.person.ui.component.PhysicalPersonFormPane;
import com.guilherme.emobiliaria.shared.di.GuiceFxmlLoader;
import com.guilherme.emobiliaria.shared.ui.ErrorHandler;
import com.guilherme.emobiliaria.shared.ui.component.WizardStepperBar;
import jakarta.inject.Inject;
import javafx.application.Platform;
import javafx.concurrent.Task;
import javafx.fxml.FXML;
import javafx.scene.Node;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.StackPane;
import javafx.stage.Stage;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;
import java.util.ResourceBundle;

public class InitialSetupController {

  private static final Logger log = LoggerFactory.getLogger(InitialSetupController.class);

  // ── Injected use cases ─────────────────────────────────────────────────────

  private final CreateAddressInteractor createAddress;
  private final SearchAddressByCepInteractor searchByCep;
  private final CreatePhysicalPersonInteractor createPhysicalPerson;
  private final CreateJuridicalPersonInteractor createJuridicalPerson;
  private final SetConfigInteractor setConfig;
  private final ValidateCpfInteractor validateCpf;
  private final ValidateCnpjInteractor validateCnpj;
  private final GuiceFxmlLoader fxmlLoader;

  @Inject
  public InitialSetupController(
      CreateAddressInteractor createAddress,
      SearchAddressByCepInteractor searchByCep,
      CreatePhysicalPersonInteractor createPhysicalPerson,
      CreateJuridicalPersonInteractor createJuridicalPerson, SetConfigInteractor setConfig,
      ValidateCpfInteractor validateCpf, ValidateCnpjInteractor validateCnpj,
      GuiceFxmlLoader fxmlLoader) {
    this.createAddress = createAddress;
    this.searchByCep = searchByCep;
    this.createPhysicalPerson = createPhysicalPerson;
    this.createJuridicalPerson = createJuridicalPerson;
    this.setConfig = setConfig;
    this.validateCpf = validateCpf;
    this.validateCnpj = validateCnpj;
    this.fxmlLoader = fxmlLoader;
  }

  // ── FXML fields ────────────────────────────────────────────────────────────

  @FXML private Label stepTitleLabel;
  @FXML private Label stepSubtitleLabel;
  @FXML private HBox stepperContainer;
  @FXML private StackPane contentPane;
  @FXML private Button backButton;
  @FXML private Button nextButton;

  // ── Wizard state ───────────────────────────────────────────────────────────

  private int currentStep = 1;
  private PersonType selectedType = null;
  private ResourceBundle bundle;

  // ── UI components ──────────────────────────────────────────────────────────

  private static final String[][] STEP_LABELS_PHYSICAL =
      {{"stepper.label.tipo"}, {"stepper.label.dados"}, {"stepper.label.endereco"}};
  private static final String[][] STEP_LABELS_JURIDICAL =
      {{"stepper.label.tipo"}, {"stepper.label.empresa"}, {"stepper.label.end_empresa"},
          {"stepper.label.representante"}, {"stepper.label.end_repres"}};
  private final AddressFormPane[] addressPane = new AddressFormPane[2];
  private PersonTypeSelectionPane typeSelectionPane;
  private PhysicalPersonFormPane physicalPersonForm;

  // ── Step label keys ────────────────────────────────────────────────────────
  private CompanyDataFormPane companyDataForm;
  private WizardStepperBar stepperBar;

  // ── Initialization ─────────────────────────────────────────────────────────

  @FXML
  public void initialize() {
    bundle = ResourceBundle.getBundle("messages", Locale.getDefault(),
        getClass().getModule());

    typeSelectionPane = new PersonTypeSelectionPane(bundle);
    physicalPersonForm = new PhysicalPersonFormPane(bundle, validateCpf);
    companyDataForm = new CompanyDataFormPane(bundle, validateCnpj);
    addressPane[0] = new AddressFormPane(searchByCep, bundle);
    addressPane[1] = new AddressFormPane(searchByCep, bundle);

    addressPane[0].setDisableNextCallback(() -> nextButton.setDisable(true),
        () -> nextButton.setDisable(false));
    addressPane[1].setDisableNextCallback(() -> nextButton.setDisable(true),
        () -> nextButton.setDisable(false));

    buildStepper();
    showStep(1);
    backButton.setOnAction(e -> handleBack());
    nextButton.setOnAction(e -> handleNext());
  }

  // ── Stepper ────────────────────────────────────────────────────────────────

  private void buildStepper() {
    List<String> labelTexts = getStepperLabelTexts();
    stepperBar = new WizardStepperBar(labelTexts);
    HBox.setHgrow(stepperBar, Priority.ALWAYS);
    stepperContainer.getChildren().setAll(stepperBar);
    stepperBar.setCurrentStep(currentStep);
  }

  private List<String> getStepperLabelTexts() {
    String[][] keys = (selectedType == PersonType.JURIDICAL)
        ? STEP_LABELS_JURIDICAL : STEP_LABELS_PHYSICAL;
    List<String> texts = new ArrayList<>();
    for (String[] key : keys) {
      texts.add(bundle.getString(key[0]));
    }
    return texts;
  }

  // ── Step navigation ────────────────────────────────────────────────────────

  private void showStep(int step) {
    contentPane.getChildren().clear();

    stepTitleLabel.setText(bundle.getString(titleKeyForStep(step)));
    stepSubtitleLabel.setText(bundle.getString(subtitleKeyForStep(step)));

    backButton.setVisible(step > 1);
    backButton.setManaged(step > 1);
    backButton.setText(bundle.getString("setup.button.back"));

    boolean isLastStep = isLastStep(step);
    nextButton.setText(isLastStep
        ? bundle.getString("setup.button.finish")
        : bundle.getString("setup.button.next"));

    contentPane.getChildren().add(buildStepContent(step));
    stepperBar.setCurrentStep(step);
  }

  private String titleKeyForStep(int step) {
    if (step == 1) return "setup.step.type.title";
    if (selectedType == PersonType.JURIDICAL) {
      return switch (step) {
        case 2 -> "setup.step.company.title";
        case 3 -> "setup.step.company_address.title";
        case 4 -> "setup.step.representative.title";
        case 5 -> "setup.step.representative_address.title";
        default -> "setup.step.type.title";
      };
    }
    return switch (step) {
      case 2 -> "setup.step.personal.title";
      case 3 -> "setup.step.address.title";
      default -> "setup.step.type.title";
    };
  }

  private String subtitleKeyForStep(int step) {
    if (step == 1) return "setup.step.type.subtitle";
    if (selectedType == PersonType.JURIDICAL) {
      return switch (step) {
        case 2 -> "setup.step.company.subtitle";
        case 3 -> "setup.step.company_address.subtitle";
        case 4 -> "setup.step.representative.subtitle";
        case 5 -> "setup.step.representative_address.subtitle";
        default -> "setup.step.type.subtitle";
      };
    }
    return switch (step) {
      case 2 -> "setup.step.personal.subtitle";
      case 3 -> "setup.step.address.subtitle";
      default -> "setup.step.type.subtitle";
    };
  }

  private boolean isLastStep(int step) {
    if (selectedType == PersonType.PHYSICAL) return step == 3;
    if (selectedType == PersonType.JURIDICAL) return step == 5;
    return false;
  }

  private Node buildStepContent(int step) {
    if (step == 1)
      return typeSelectionPane;
    if (selectedType == PersonType.JURIDICAL) {
      return switch (step) {
        case 2 -> companyDataForm;
        case 3 -> addressPane[0];
        case 4 -> physicalPersonForm;
        case 5 -> addressPane[1];
        default -> typeSelectionPane;
      };
    }
    return switch (step) {
      case 2 -> physicalPersonForm;
      case 3 -> addressPane[0];
      default -> typeSelectionPane;
    };
  }

  private void handleNext() {
    if (!validateCurrentStep()) return;

    if (currentStep == 1) {
      selectedType = typeSelectionPane.getSelectedType();
      buildStepper();
    }

    if (isLastStep(currentStep)) {
      handleSubmit();
      return;
    }

    currentStep++;
    showStep(currentStep);
  }

  private void handleBack() {
    if (currentStep <= 1) return;
    currentStep--;
    showStep(currentStep);
  }

  // ── Validation ─────────────────────────────────────────────────────────────

  private boolean validateCurrentStep() {
    if (currentStep == 1)
      return typeSelectionPane.validate();

    if (selectedType == PersonType.JURIDICAL) {
      return switch (currentStep) {
        case 2 -> companyDataForm.validate();
        case 3 -> addressPane[0].validate();
        case 4 -> physicalPersonForm.validate();
        case 5 -> addressPane[1].validate();
        default -> true;
      };
    }
    return switch (currentStep) {
      case 2 -> physicalPersonForm.validate();
      case 3 -> addressPane[0].validate();
      default -> true;
    };
  }

  // ── Submission ─────────────────────────────────────────────────────────────

  private void handleSubmit() {
    nextButton.setDisable(true);
    backButton.setDisable(true);

    if (selectedType == PersonType.PHYSICAL) {
      submitPhysicalFlow();
    } else {
      submitJuridicalFlow();
    }
  }

  private void submitPhysicalFlow() {
    Task<CreateAddressOutput> addressTask = new Task<>() {
      @Override protected CreateAddressOutput call() {
        return createAddress.execute(addressPane[0].buildInput());
      }
    };

    addressTask.setOnSucceeded(e -> {
      long addressId = addressTask.getValue().address().getId();

      Task<CreatePhysicalPersonOutput> personTask = new Task<>() {
        @Override protected CreatePhysicalPersonOutput call() {
          return createPhysicalPerson.execute(physicalPersonForm.buildInput(addressId));
        }
      };

      personTask.setOnSucceeded(pe -> {
        long personId = personTask.getValue().physicalPerson().getId();

        Task<Void> configTask = new Task<>() {
          @Override protected Void call() {
            setConfig.execute(new SetConfigInput(personId, "PHYSICAL"));
            return null;
          }
        };

        configTask.setOnSucceeded(ce -> navigateToMain());
        configTask.setOnFailed(ce -> handleError(configTask.getException()));
        new Thread(configTask).start();
      });

      personTask.setOnFailed(pe -> handleError(personTask.getException()));
      new Thread(personTask).start();
    });

    addressTask.setOnFailed(e -> handleError(addressTask.getException()));
    new Thread(addressTask).start();
  }

  private void submitJuridicalFlow() {
    Task<CreateAddressOutput> companyAddrTask = new Task<>() {
      @Override protected CreateAddressOutput call() {
        return createAddress.execute(addressPane[0].buildInput());
      }
    };

    companyAddrTask.setOnSucceeded(e -> {
      long companyAddressId = companyAddrTask.getValue().address().getId();

      Task<CreateAddressOutput> reprAddrTask = new Task<>() {
        @Override protected CreateAddressOutput call() {
          return createAddress.execute(addressPane[1].buildInput());
        }
      };

      reprAddrTask.setOnSucceeded(e2 -> {
        long reprAddressId = reprAddrTask.getValue().address().getId();

        Task<CreatePhysicalPersonOutput> reprPersonTask = new Task<>() {
          @Override protected CreatePhysicalPersonOutput call() {
            return createPhysicalPerson.execute(physicalPersonForm.buildInput(reprAddressId));
          }
        };

        reprPersonTask.setOnSucceeded(e3 -> {
          long reprPersonId = reprPersonTask.getValue().physicalPerson().getId();

          Task<CreateJuridicalPersonOutput> juridicalTask = new Task<>() {
            @Override protected CreateJuridicalPersonOutput call() {
              return createJuridicalPerson.execute(new CreateJuridicalPersonInput(
                  companyDataForm.getCorporateName(), companyDataForm.getCnpj(),
                  List.of(reprPersonId),
                  companyAddressId
              ));
            }
          };

          juridicalTask.setOnSucceeded(e4 -> {
            long juridicalId = juridicalTask.getValue().juridicalPerson().getId();

            Task<Void> configTask = new Task<>() {
              @Override protected Void call() {
                setConfig.execute(new SetConfigInput(juridicalId, "JURIDICAL"));
                return null;
              }
            };

            configTask.setOnSucceeded(e5 -> navigateToMain());
            configTask.setOnFailed(e5 -> handleError(configTask.getException()));
            new Thread(configTask).start();
          });

          juridicalTask.setOnFailed(e4 -> handleError(juridicalTask.getException()));
          new Thread(juridicalTask).start();
        });

        reprPersonTask.setOnFailed(e3 -> handleError(reprPersonTask.getException()));
        new Thread(reprPersonTask).start();
      });

      reprAddrTask.setOnFailed(e2 -> handleError(reprAddrTask.getException()));
      new Thread(reprAddrTask).start();
    });

    companyAddrTask.setOnFailed(e -> handleError(companyAddrTask.getException()));
    new Thread(companyAddrTask).start();
  }

  private void navigateToMain() {
    try {
      Stage stage = (Stage) nextButton.getScene().getWindow();
      Parent mainView = fxmlLoader.load(InitialSetupController.class.getResource(
          "/com/guilherme/emobiliaria/shared/ui/layout/view/main-view.fxml"));
      Scene scene = new Scene(mainView);
      stage.setScene(scene);
      stage.setTitle("e-Mobiliária");
      stage.setResizable(true);
    } catch (IOException e) {
      log.error("Failed to load main view", e);
      handleError(e);
    }
  }

  private void handleError(Throwable t) {
    Platform.runLater(() -> {
      nextButton.setDisable(false);
      backButton.setDisable(false);
    });
    ErrorHandler.handle(t, bundle);
  }
}

package com.guilherme.emobiliaria.contract.infrastructure.repository;

import com.guilherme.emobiliaria.contract.domain.entity.Contract;
import com.guilherme.emobiliaria.contract.domain.entity.PaymentAccount;
import com.guilherme.emobiliaria.contract.domain.repository.ContractRepository;
import com.guilherme.emobiliaria.person.domain.entity.Address;
import com.guilherme.emobiliaria.person.domain.entity.BrazilianState;
import com.guilherme.emobiliaria.person.domain.entity.CivilState;
import com.guilherme.emobiliaria.person.domain.entity.JuridicalPerson;
import com.guilherme.emobiliaria.person.domain.entity.Person;
import com.guilherme.emobiliaria.person.domain.entity.PhysicalPerson;
import com.guilherme.emobiliaria.property.domain.entity.Property;
import com.guilherme.emobiliaria.shared.exception.ErrorMessage;
import com.guilherme.emobiliaria.shared.exception.PersistenceException;
import com.guilherme.emobiliaria.shared.persistence.PagedResult;
import com.guilherme.emobiliaria.shared.persistence.PaginationInput;
import jakarta.inject.Inject;

import javax.sql.DataSource;
import java.sql.Connection;
import java.sql.Date;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;
import java.time.Period;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

public class JdbcContractRepository implements ContractRepository {

  private final DataSource dataSource;

  @Inject
  public JdbcContractRepository(DataSource dataSource) {
    this.dataSource = dataSource;
  }

  @Override
  public Contract create(Contract contract) {
    String sql = "INSERT INTO contracts (start_date, duration, payment_day, rent, purpose, payment_account_id, property_id, landlord_id, landlord_type) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)";
    try (Connection conn = dataSource.getConnection();
        PreparedStatement stmt = conn.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS)) {
      stmt.setDate(1, Date.valueOf(contract.getStartDate()));
      stmt.setString(2, contract.getDuration().toString());
      stmt.setInt(3, contract.getPaymentDay());
      stmt.setInt(4, contract.getRent());
      stmt.setString(5, contract.getPurpose());
      stmt.setLong(6, contract.getPaymentAccount().getId());
      stmt.setLong(7, contract.getProperty().getId());
      stmt.setLong(8, contract.getLandlord().getId());
      stmt.setString(9, personType(contract.getLandlord()));
      stmt.executeUpdate();
      try (ResultSet keys = stmt.getGeneratedKeys()) {
        keys.next();
        contract.setId(keys.getLong(1));
      }
      insertTenants(conn, contract.getId(), contract.getTenants());
      insertGuarantors(conn, contract.getId(), contract.getGuarantors());
      insertWitnesses(conn, contract.getId(), contract.getWitnesses());
      return contract;
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Contract.NOT_FOUND, e);
    }
  }

  @Override
  public Contract update(Contract contract) {
    String sql = "UPDATE contracts SET start_date=?, duration=?, payment_day=?, rent=?, purpose=?, payment_account_id=?, property_id=?, landlord_id=?, landlord_type=? WHERE id=?";
    try (Connection conn = dataSource.getConnection();
        PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setDate(1, Date.valueOf(contract.getStartDate()));
      stmt.setString(2, contract.getDuration().toString());
      stmt.setInt(3, contract.getPaymentDay());
      stmt.setInt(4, contract.getRent());
      stmt.setString(5, contract.getPurpose());
      stmt.setLong(6, contract.getPaymentAccount().getId());
      stmt.setLong(7, contract.getProperty().getId());
      stmt.setLong(8, contract.getLandlord().getId());
      stmt.setString(9, personType(contract.getLandlord()));
      stmt.setLong(10, contract.getId());
      if (stmt.executeUpdate() == 0) {
        throw new PersistenceException(ErrorMessage.Contract.NOT_FOUND, null);
      }
      deleteTenants(conn, contract.getId());
      insertTenants(conn, contract.getId(), contract.getTenants());
      deleteGuarantors(conn, contract.getId());
      insertGuarantors(conn, contract.getId(), contract.getGuarantors());
      deleteWitnesses(conn, contract.getId());
      insertWitnesses(conn, contract.getId(), contract.getWitnesses());
      return contract;
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Contract.NOT_FOUND, e);
    }
  }

  @Override
  public void delete(Long id) {
    String sql = "DELETE FROM contracts WHERE id=?";
    try (Connection conn = dataSource.getConnection();
        PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      if (stmt.executeUpdate() == 0) {
        throw new PersistenceException(ErrorMessage.Contract.NOT_FOUND, null);
      }
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Contract.NOT_FOUND, e);
    }
  }

  @Override
  public Optional<Contract> findById(Long id) {
    String sql = "SELECT id, start_date, duration, payment_day, rent, purpose, payment_account_id, property_id, landlord_id, landlord_type FROM contracts WHERE id=?";
    try (Connection conn = dataSource.getConnection();
        PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        if (!rs.next()) {
          return Optional.empty();
        }
        return Optional.of(map(rs, conn));
      }
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Contract.NOT_FOUND, e);
    }
  }

  @Override
  public PagedResult<Contract> findAll(PaginationInput pagination) {
    int limit = pagination.limit() != null ? pagination.limit() : Integer.MAX_VALUE;
    int offset = pagination.offset() != null ? pagination.offset() : 0;
    try (Connection conn = dataSource.getConnection()) {
      long total;
      try (PreparedStatement countStmt = conn.prepareStatement("SELECT COUNT(*) FROM contracts");
          ResultSet countRs = countStmt.executeQuery()) {
        countRs.next();
        total = countRs.getLong(1);
      }
      String sql = "SELECT id, start_date, duration, payment_day, rent, purpose, payment_account_id, property_id, landlord_id, landlord_type FROM contracts LIMIT ? OFFSET ?";
      try (PreparedStatement stmt = conn.prepareStatement(sql)) {
        stmt.setInt(1, limit);
        stmt.setInt(2, offset);
        try (ResultSet rs = stmt.executeQuery()) {
          List<Contract> items = new ArrayList<>();
          while (rs.next()) {
            items.add(map(rs, conn));
          }
          return new PagedResult<>(items, total);
        }
      }
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Contract.NOT_FOUND, e);
    }
  }

  @Override
  public PagedResult<Contract> findAllByPropertyId(Long propertyId, PaginationInput pagination) {
    int limit = pagination.limit() != null ? pagination.limit() : Integer.MAX_VALUE;
    int offset = pagination.offset() != null ? pagination.offset() : 0;
    try (Connection conn = dataSource.getConnection()) {
      long total;
      try (PreparedStatement countStmt = conn.prepareStatement("SELECT COUNT(*) FROM contracts WHERE property_id=?")) {
        countStmt.setLong(1, propertyId);
        try (ResultSet countRs = countStmt.executeQuery()) {
          countRs.next();
          total = countRs.getLong(1);
        }
      }
      String sql = "SELECT id, start_date, duration, payment_day, rent, purpose, payment_account_id, property_id, landlord_id, landlord_type FROM contracts WHERE property_id=? LIMIT ? OFFSET ?";
      try (PreparedStatement stmt = conn.prepareStatement(sql)) {
        stmt.setLong(1, propertyId);
        stmt.setInt(2, limit);
        stmt.setInt(3, offset);
        try (ResultSet rs = stmt.executeQuery()) {
          List<Contract> items = new ArrayList<>();
          while (rs.next()) {
            items.add(map(rs, conn));
          }
          return new PagedResult<>(items, total);
        }
      }
    } catch (SQLException e) {
      throw new PersistenceException(ErrorMessage.Contract.NOT_FOUND, e);
    }
  }

  private Contract map(ResultSet rs, Connection conn) throws SQLException {
    long id = rs.getLong("id");
    Period duration = Period.parse(rs.getString("duration"));
    PaymentAccount paymentAccount = loadPaymentAccount(conn, rs.getLong("payment_account_id"));
    Property property = loadProperty(conn, rs.getLong("property_id"));
    Person landlord = loadPerson(conn, rs.getLong("landlord_id"), rs.getString("landlord_type"));
    List<Person> tenants = loadTenants(conn, id);
    List<Person> guarantors = loadGuarantors(conn, id);
    List<Person> witnesses = loadWitnesses(conn, id);
    return Contract.restore(
        id,
        rs.getDate("start_date").toLocalDate(),
        duration,
        rs.getInt("payment_day"),
        rs.getInt("rent"),
        rs.getString("purpose"),
        paymentAccount,
        property,
        landlord,
        tenants,
        guarantors,
        witnesses
    );
  }

  private PaymentAccount loadPaymentAccount(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, bank, bank_branch, account_number, pix_key FROM payment_accounts WHERE id=?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        return PaymentAccount.restore(
            rs.getLong("id"),
            rs.getString("bank"),
            rs.getString("bank_branch"),
            rs.getString("account_number"),
            rs.getString("pix_key")
        );
      }
    }
  }

  private Property loadProperty(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, name, type, cemig, copasa, iptu, address_id FROM properties WHERE id=?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        Address address = loadAddress(conn, rs.getLong("address_id"));
        return Property.restore(
            rs.getLong("id"),
            rs.getString("name"),
            rs.getString("type"),
            rs.getString("cemig"),
            rs.getString("copasa"),
            rs.getString("iptu"),
            address
        );
      }
    }
  }

  private Person loadPerson(Connection conn, long id, String type) throws SQLException {
    if ("PHYSICAL".equals(type)) {
      return loadPhysicalPerson(conn, id);
    }
    return loadJuridicalPerson(conn, id);
  }

  private PhysicalPerson loadPhysicalPerson(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, name, nationality, civil_state, occupation, cpf, id_card_number, address_id FROM physical_persons WHERE id=?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        Address address = loadAddress(conn, rs.getLong("address_id"));
        return PhysicalPerson.restore(
            rs.getLong("id"),
            rs.getString("name"),
            rs.getString("nationality"),
            CivilState.valueOf(rs.getString("civil_state")),
            rs.getString("occupation"),
            rs.getString("cpf"),
            rs.getString("id_card_number"),
            address
        );
      }
    }
  }

  private JuridicalPerson loadJuridicalPerson(Connection conn, long id) throws SQLException {
    String sql = "SELECT id, corporate_name, cnpj, representative_id, address_id FROM juridical_persons WHERE id=?";
    try (PreparedStatement stmt = conn.prepareStatement(sql)) {
      stmt.setLong(1, id);
      try (ResultSet rs = stmt.executeQuery()) {
        rs.next();
        PhysicalPerson representative = loadPhysicalPerson(conn, rs.getLong("representative_id"));
        Address address = loadAddress(conn, rs.getLong("address_id"));
        return JuridicalPerson.restore(
            rs.getLong("id"),
            rs.getString("corporate_name"),
            rs.getString("cnpj"),
            representative,
            address
